const _ = require("lodash");
const problemsData = require("../../data/problems.json");

/**
 * Filters problems by difficulty, tags, and applies limit.
 * @param {Object[]} problems
 * @param {string} difficulty
 * @param {string[]} tags
 * @param {number} limit
 * @returns {Object[]}
 */
function filterAndLimitProblems(problems, difficulty, tags, limit) {
  let filtered = problems;

  if (difficulty) {
    filtered = filtered.filter(p => p.difficulty === difficulty);
  }

  if (tags && tags.length > 0) {
    filtered = filtered.filter(p => tags.every(tag => p.tags.includes(tag)));
  }

  if (limit && limit > 0) {
    filtered = filtered.slice(0, limit);
  }

  return filtered;
}

/**
 * Computes language totals for a list of problems.
 * @param {Object[]} problems
 * @returns {Object} language -> count
 */
function computeLanguageTotals(problems) {
  const totals = {};
  problems.forEach(problem => {
    if (problem.language) {
      totals[problem.language] = (totals[problem.language] || 0) + 1;
    }
  });
  return totals;
}

/**
 * Computes status totals for a list of problems.
 * @param {Object[]} problems
 * @returns {Object} status -> count
 */
function computeStatusTotals(problems) {
  const totals = {};
  problems.forEach(problem => {
    if (problem.status) {
      totals[problem.status] = (totals[problem.status] || 0) + 1;
    }
  });
  return totals;
}

/**
 * Lists problems with optional filters and metadata including component totals.
 * @param {Object} params
 * @param {string} [params.difficulty]
 * @param {string[]} [params.tags]
 * @param {number} [params.limit]
 * @param {boolean} [params.includeComponents]
 * @returns {Object} { problems: Object[], metadata: Object }
 */
function listProblems(params) {
  const difficulty = params.difficulty || null;
  const tags = params.tags || [];
  const limit = params.limit || null;
  const includeComponents = params.includeComponents || false;

  // Filter and limit problems
  const filteredProblems = filterAndLimitProblems(problemsData, difficulty, tags, limit);

  const metadata = {};

  if (includeComponents) {
    // Compute language totals and status totals for filtered+limited problems
    metadata.componentLanguageTotals = computeLanguageTotals(filteredProblems);
    metadata.componentStatusTotals = computeStatusTotals(filteredProblems);
  }

  return {
    problems: filteredProblems,
    metadata
  };
}

module.exports = {
  listProblems
};
